import hmac
import hashlib
import struct
import time
import base64
import os
import io
import json
from pathlib import Path

try:
    import qrcode
    HAS_QRCODE = True
except ImportError:
    HAS_QRCODE = False


class TOTPAuthenticator:
    """TOTP (Time-based One-Time Password) two-factor authentication system."""

    def __init__(self, storage_file="totp_users.json", digits=6, interval=30, algorithm="sha1", window=1):
        """
        Initialize TOTP Authenticator.

        Args:
            storage_file: Path to JSON file for storing user secrets.
            digits: Number of digits in the TOTP code (default 6).
            interval: Time step in seconds (default 30).
            algorithm: Hash algorithm to use (default sha1).
            window: Number of time steps to check before/after current (default 1).
        """
        self.storage_file = Path(storage_file)
        self.digits = digits
        self.interval = interval
        self.algorithm = algorithm
        self.window = window
        self.users = self._load_users()

    def _load_users(self):
        """Load users from storage file."""
        if self.storage_file.exists():
            with open(self.storage_file, "r") as f:
                return json.load(f)
        return {}

    def _save_users(self):
        """Save users to storage file."""
        with open(self.storage_file, "w") as f:
            json.dump(self.users, f, indent=2)

    @staticmethod
    def generate_secret(length=20):
        """
        Generate a random secret key.

        Args:
            length: Length of the secret in bytes (default 20 for SHA1).

        Returns:
            Base32-encoded secret string.
        """
        random_bytes = os.urandom(length)
        secret = base64.b32encode(random_bytes).decode("utf-8").rstrip("=")
        return secret

    @staticmethod
    def _decode_secret(secret):
        """Decode a base32-encoded secret, adding padding if necessary."""
        # Add padding if needed
        missing_padding = len(secret) % 8
        if missing_padding:
            secret += "=" * (8 - missing_padding)
        return base64.b32decode(secret.upper())

    def _get_hash_function(self):
        """Get the hash function based on the algorithm setting."""
        algorithms = {
            "sha1": hashlib.sha1,
            "sha256": hashlib.sha256,
            "sha512": hashlib.sha512,
        }
        if self.algorithm not in algorithms:
            raise ValueError(f"Unsupported algorithm: {self.algorithm}. Use one of {list(algorithms.keys())}")
        return algorithms[self.algorithm]

    def _generate_hotp(self, secret_bytes, counter):
        """
        Generate an HOTP value.

        Args:
            secret_bytes: The decoded secret key bytes.
            counter: The counter value (8-byte big-endian integer).

        Returns:
            HOTP code as a zero-padded string.
        """
        hash_func = self._get_hash_function()

        # Pack counter as 8-byte big-endian
        counter_bytes = struct.pack(">Q", counter)

        # Compute HMAC
        hmac_digest = hmac.new(secret_bytes, counter_bytes, hash_func).digest()

        # Dynamic truncation
        offset = hmac_digest[-1] & 0x0F
        truncated = struct.unpack(">I", hmac_digest[offset:offset + 4])[0]
        truncated &= 0x7FFFFFFF

        # Generate code with proper number of digits
        code = truncated % (10 ** self.digits)
        return str(code).zfill(self.digits)

    def generate_totp(self, secret, timestamp=None):
        """
        Generate a TOTP code for the given secret and time.

        Args:
            secret: Base32-encoded secret string.
            timestamp: Unix timestamp (default: current time).

        Returns:
            TOTP code as a string.
        """
        if timestamp is None:
            timestamp = time.time()

        secret_bytes = self._decode_secret(secret)
        counter = int(timestamp) // self.interval
        return self._generate_hotp(secret_bytes, counter)

    def verify_totp(self, secret, code, timestamp=None):
        """
        Verify a TOTP code against the secret.

        Checks the current time step and a configurable window of steps
        before and after to account for clock drift.

        Args:
            secret: Base32-encoded secret string.
            code: The TOTP code to verify.
            timestamp: Unix timestamp (default: current time).

        Returns:
            True if the code is valid, False otherwise.
        """
        if timestamp is None:
            timestamp = time.time()

        code = str(code).zfill(self.digits)
        secret_bytes = self._decode_secret(secret)
        current_counter = int(timestamp) // self.interval

        for offset in range(-self.window, self.window + 1):
            counter = current_counter + offset
            expected_code = self._generate_hotp(secret_bytes, counter)
            if hmac.compare_digest(code, expected_code):
                return True

        return False

    def get_provisioning_uri(self, secret, username, issuer="MFASystem"):
        """
        Generate an otpauth:// URI for provisioning authenticator apps.

        Args:
            secret: Base32-encoded secret string.
            username: The username/account name.
            issuer: The issuer name (default: MFASystem).

        Returns:
            otpauth:// URI string.
        """
        # Ensure proper base32 encoding (no padding in URI)
        secret_clean = secret.replace("=", "").upper()

        # URL-encode components
        from urllib.parse import quote
        label = f"{quote(issuer)}:{quote(username)}"
        params = (
            f"secret={secret_clean}"
            f"&issuer={quote(issuer)}"
            f"&algorithm={self.algorithm.upper()}"
            f"&digits={self.digits}"
            f"&period={self.interval}"
        )
        return f"otpauth://totp/{label}?{params}"

    def generate_qr_code(self, secret, username, issuer="MFASystem", output_path=None):
        """
        Generate a QR code for the TOTP provisioning URI.

        Args:
            secret: Base32-encoded secret string.
            username: The username/account name.
            issuer: The issuer name.
            output_path: Path to save the QR code image (optional).

        Returns:
            Tuple of (provisioning_uri, qr_image_bytes or file_path).
        """
        uri = self.get_provisioning_uri(secret, username, issuer)

        if not HAS_QRCODE:
            print("WARNING: 'qrcode' library not installed. Install with: pip install qrcode[pil]")
            print(f"Provisioning URI (enter manually in your authenticator app):\n{uri}")
            # Return ASCII art representation
            ascii_qr = self._generate_ascii_qr(uri)
            return uri, ascii_qr

        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(uri)
        qr.make(fit=True)

        img = qr.make_image(fill_color="black", back_color="white")

        if output_path:
            img.save(output_path)
            return uri, output_path
        else:
            buffer = io.BytesIO()
            img.save(buffer, format="PNG")
            return uri, buffer.getvalue()

    @staticmethod
    def _generate_ascii_qr(data):
        """Generate a simple ASCII representation hint for QR code."""
        return f"[QR Code for: {data}]\n(Install 'qrcode' package for actual QR code generation)"

    def register_user(self, username, issuer="MFASystem"):
        """
        Register a new user for TOTP 2FA.

        Args:
            username: The username to register.
            issuer: The issuer name.

        Returns:
            Dictionary with secret, provisioning URI, and QR code info.
        """
        if username in self.users and self.users[username].get("verified"):
            raise ValueError(f"User '{username}' is already registered and verified.")

        secret = self.generate_secret()
        uri = self.get_provisioning_uri(secret, username, issuer)

        self.users[username] = {
            "secret": secret,
            "verified": False,
            "created_at": time.time(),
            "issuer": issuer,
        }
        self._save_users()

        # Generate QR code
        _, qr_result = self.generate_qr_code(secret, username, issuer)

        result = {
            "username": username,
            "secret": secret,
            "provisioning_uri": uri,
            "qr_code": qr_result,
            "message": "Scan the QR code with your authenticator app, then verify with a code.",
        }

        print(f"\n{'='*60}")
        print(f"TOTP Registration for: {username}")
        print(f"{'='*60}")
        print(f"Secret Key: {secret}")
        print(f"Provisioning URI: {uri}")
        print(f"{'='*60}")
        print("Scan the QR code or manually enter the secret in your authenticator app.")
        print(f"{'='*60}\n")

        return result

    def verify_registration(self, username, code):
        """
        Verify the initial TOTP code to complete registration.

        Args:
            username: The username.
            code: The TOTP code from the authenticator app.

        Returns:
            True if verification succeeded.
        """
        if username not in self.users:
            raise ValueError(f"User '{username}' not found.")

        secret = self.users[username]["secret"]

        if self.verify_totp(secret, code):
            self.users[username]["verified"] = True
            self.users[username]["verified_at"] = time.time()
            self._save_users()
            print(f"✓ User '{username}' TOTP registration verified successfully!")
            return True
        else:
            print(f"✗ Invalid code for user '{username}'. Please try again.")
            return False

    def authenticate(self, username, code):
        """
        Authenticate a user with their TOTP code.

        Args:
            username: The username.
            code: The TOTP code to verify.

        Returns:
            True if authentication succeeded, False otherwise.
        """
        if username not in self.users:
            print(f"✗ User '{username}' not found.")
            return False

        if not self.users[username].get("verified"):
            print(f"✗ User '{username}' has not completed TOTP registration.")
            return False

        secret = self.users[username]["secret"]
        is_valid = self.verify_totp(secret, code)

        if is_valid:
            print(f"✓ Authentication successful for user '{username}'.")
        else:
            print(f"✗ Authentication failed for user '{username}'. Invalid code.")

        return is_valid

    def remove_user(self, username):
        """
        Remove a user's TOTP registration.

        Args:
            username: The username to remove.
        """
        if username not in self.users:
            raise ValueError(f"User '{username}' not found.")

        del self.users[username]
        self._save_users()
        print(f"User '{username}' TOTP registration removed.")

    def list_users(self):
        """List all registered users and their status."""
        if not self.users:
            print("No users registered.")
            return []

        print(f"\n{'Username':<20} {'Verified':<10} {'Created At':<25}")
        print("-" * 55)
        for username, data in self.users.items():
            verified = "Yes" if data.get("verified") else "No"
            created = time.strftime("%Y-%m-%d %H:%M:%S", time.localtime(data.get("created_at", 0)))
            print(f"{username:<20} {verified:<10} {created:<25}")
        print()
        return list(self.users.keys())

    def get_remaining_seconds(self):
        """Get the number of seconds remaining in the current time step."""
        return self.interval - (int(time.time()) % self.interval)

    def generate_backup_codes(self, username, count=10):
        """
        Generate backup codes for a user in case they lose access to their authenticator.

        Args:
            username: The username.
            count: Number of backup codes to generate.

        Returns:
            List of backup codes.
        """
        if username not in self.users:
            raise ValueError(f"User '{username}' not found.")

        codes = []
        for _ in range(count):
            code = base64.b32encode(os.urandom(5)).decode("utf-8").rstrip("=")[:8]
            codes.append(code)

        # Store hashed backup codes
        hashed_codes = [hashlib.sha256(c.encode()).hexdigest() for c in codes]
        self.users[username]["backup_codes"] = hashed_codes
        self._save_users()

        print(f"\nBackup codes for '{username}':")
        print("=" * 30)
        for i, code in enumerate(codes, 1):
            print(f"  {i:2d}. {code}")
        print("=" * 30)
        print("Store these codes securely. Each can only be used once.\n")

        return codes

    def verify_backup_code(self, username, code):
        """
        Verify and consume a backup code.

        Args:
            username: The username.
            code: The backup code to verify.

        Returns:
            True if the backup code is valid.
        """
        if username not in self.users:
            return False

        backup_codes = self.users[username].get("backup_codes", [])
        code_hash = hashlib.sha256(code.encode()).hexdigest()

        if code_hash in backup_codes:
            backup_codes.remove(code_hash)
            self.users[username]["backup_codes"] = backup_codes
            self._save_users()
            print(f"✓ Backup code accepted for '{username}'. {len(backup_codes)} codes remaining.")
            return True

        print(f"✗ Invalid backup code for '{username}'.")
        return False


