        print("5. Verify backup code")
        print("6. List users")
        print("7. Remove user")
        print("8. Show current code (for testing)")
        print("9. Exit")
        print("-" * 40)

        choice = input("Select option: ").strip()

        try:
            if choice == "1":
                username = input("Enter username/email: ").strip()
                issuer = input("Enter issuer name (default: MFASystem): ").strip() or "MFASystem"
                result = auth.register_user(username, issuer)
                qr_path = f"qr_{username.replace('@', '_').replace('.', '_')}.png"
                if HAS_QRCODE:
                    auth.generate_qr_code(result["secret"], username, issuer, output_path=qr_path)
                    print(f"QR code saved to: {qr_path}")

            elif choice == "2":
                username = input("Enter username/email: ").strip()
                code = input("Enter TOTP code from authenticator app: ").strip()
                auth.verify_registration(username, code)

            elif choice == "3":
                username = input("Enter username/email: ").strip()
                code = input("Enter TOTP code: ").strip()
                auth.authenticate(username, code)

            elif choice == "4":
                username = input("Enter username/email: ").strip()
                auth.generate_backup_codes(username)

            elif choice == "5":
                username = input("Enter username/email: ").strip()
                code = input("Enter backup code: ").strip()
                auth.verify_backup_code(username, code)

            elif choice == "6":
                auth.list_users()

            elif choice == "7":
                username = input("Enter username/email to remove: ").strip()
                confirm = input(f"Are you sure you want to remove '{username}'? (yes/no): ").strip()
                if confirm.lower() == "yes":
                    auth.remove_user(username)

            elif choice == "8":
                username = input("Enter username/email: ").strip()
                if username in auth.users:
                    secret = auth.users[username]["secret"]
                    code = auth.generate_totp(secret)
                    remaining = auth.get_remaining_seconds()
                    print(f"Current code: {code} (expires in {remaining}s)")
                else:
                    print(f"User '{username}' not found.")

            elif choice == "9":
                print("Goodbye!")
                break

            else:
                print("Invalid option. Please try again.")

        except Exception as e:
            print(f"Error: {e}")


